import{_ as t,o as s,c as o,a2 as a}from"./chunks/framework._O8Cueap.js";const p=JSON.parse('{"title":"Conversations","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/conversations.md","filePath":"concepts/conversations.md"}'),n={name:"concepts/conversations.md"};function i(r,e,l,c,d,h){return s(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="conversations" tabindex="-1">Conversations <a class="header-anchor" href="#conversations" aria-label="Permalink to &quot;Conversations&quot;">​</a></h1><p>Conversations let users chat directly with an agent outside the workflow engine.</p><h2 id="what-a-conversation-is" tabindex="-1">What a Conversation Is <a class="header-anchor" href="#what-a-conversation-is" aria-label="Permalink to &quot;What a Conversation Is&quot;">​</a></h2><ul><li>A conversation is a persisted thread between one user and one selected agent.</li><li>Each conversation belongs to a workspace and is recorded in the database.</li><li>The conversation history is stored as ordered <code>user</code> and <code>assistant</code> messages, so users can leave and resume later.</li><li>The selected agent can be switched later from the conversation screen, so subsequent turns can continue with a different active agent while keeping the same transcript.</li></ul><h2 id="starting-a-conversation" tabindex="-1">Starting a Conversation <a class="header-anchor" href="#starting-a-conversation" aria-label="Permalink to &quot;Starting a Conversation&quot;">​</a></h2><ul><li>Open <strong>Conversations</strong> from the workspace navigation and create a new thread.</li><li>Choose one active agent from the available agent list.</li><li>Optionally provide a title; otherwise OAO generates one automatically.</li><li>Agent detail pages include a <strong>Start Conversation</strong> shortcut that preselects that agent.</li></ul><h2 id="interactive-behavior" tabindex="-1">Interactive Behavior <a class="header-anchor" href="#interactive-behavior" aria-label="Permalink to &quot;Interactive Behavior&quot;">​</a></h2><ul><li>Messages are stored immediately when the user sends them.</li><li>The assistant response is created as a pending message and then streamed into the UI as deltas arrive.</li><li>Conversation pages subscribe to server-sent events (SSE), so the transcript updates while the agent is still responding.</li><li>The stream can include visible reasoning blocks, reasoning deltas, turn lifecycle markers, and tool execution events so the UI can show what the agent is doing while a turn is running.</li><li>Only one assistant turn can run at a time for a conversation.</li></ul><h2 id="conversation-controls" tabindex="-1">Conversation Controls <a class="header-anchor" href="#conversation-controls" aria-label="Permalink to &quot;Conversation Controls&quot;">​</a></h2><ul><li>The conversation page can override the next turn&#39;s model selection using the active records from the workspace <strong>Models</strong> registry.</li><li>The conversation page can override the next turn&#39;s reasoning effort (<code>low</code>, <code>medium</code>, <code>high</code>, <code>xhigh</code>) when the chosen model supports it.</li><li>The conversation page can override the agent&#39;s tool defaults by selecting or clearing both built-in tools and discovered MCP tools for the next turn.</li><li>These per-turn settings are stored in conversation message metadata so the UI can restore the last-used settings for the thread.</li></ul><p>The turn controls live in a compact bar directly below the prompt input, similar to editor-integrated chat tools. Agent, model, and reasoning selectors stay inline, while tools open in a popup tree so the transcript keeps most of the available screen space.</p><p>The tool selector uses the same grouped catalog model as the agent editor:</p><ul><li>Built-in tools are grouped by capability area.</li><li>The default OAO Platform MCP server is auto-included.</li><li>Stored MCP servers and template-defined MCP servers appear as separate groups.</li><li>Resetting the selector returns the conversation to the current agent defaults.</li></ul><h2 id="agent-context" tabindex="-1">Agent Context <a class="header-anchor" href="#agent-context" aria-label="Permalink to &quot;Agent Context&quot;">​</a></h2><ul><li>Conversations use the selected agent&#39;s markdown instructions, skills, built-in tools, MCP servers, and scoped variables.</li><li>Workflow-specific tools such as workflow editing and self-scheduling are intentionally excluded from conversation sessions because there is no workflow execution context.</li><li>The same per-agent session lock used by workflow steps also applies to conversations, so an agent cannot run conflicting Copilot sessions at the same time.</li></ul><h2 id="per-session-auto-approval" tabindex="-1">Per-Session Auto-Approval <a class="header-anchor" href="#per-session-auto-approval" aria-label="Permalink to &quot;Per-Session Auto-Approval&quot;">​</a></h2><p>Each assistant response is its own Copilot SDK session. OAO creates the session with <code>onPermissionRequest: approveAll</code>, which means every tool call the agent makes during that session is automatically approved without prompting the user. This applies to both built-in tools (e.g. <code>read_variables</code>, <code>simple_http_request</code>) and any MCP-provided tools enabled for the conversation.</p><p>If the agent needs to ask the user for input mid-session (rather than for tool permission), it should call the <strong><code>ask_questions</code></strong> built-in tool — see below.</p><h2 id="asking-the-user-questions-mid-session-—-ask-questions" tabindex="-1">Asking the User Questions Mid-Session — <code>ask_questions</code> <a class="header-anchor" href="#asking-the-user-questions-mid-session-—-ask-questions" aria-label="Permalink to &quot;Asking the User Questions Mid-Session — `ask_questions`&quot;">​</a></h2><p>The <code>ask_questions</code> built-in tool lets an agent pause its current Copilot session, present the user with a structured form, and resume once the user answers.</p><ul><li><strong>Question types</strong> — <code>single_choice</code>, <code>multi_choice</code>, and <code>free_text</code> are supported.</li><li><strong>Choice questions</strong> can set <code>allowOther: true</code> to render an &quot;Other&quot; option that reveals a free-text input alongside the chosen value.</li><li><strong><code>required: false</code></strong> lets a free-text question be skipped.</li><li><strong><code>introduction</code></strong> is shown above the form to give the user context.</li><li><strong><code>timeoutSeconds</code></strong> caps how long the agent waits (default 600s, max 3600s). On timeout the tool returns an error and the agent decides how to proceed.</li></ul><p>The flow:</p><ol><li>Agent calls <code>ask_questions({ questions: [...] })</code>.</li><li>OAO emits a <code>conversation.tool.ask_questions</code> SSE event with the question payload and a unique <code>askId</code>.</li><li>The conversation page renders the form below the active assistant message.</li><li>When the user submits, the UI POSTs <code>/api/conversations/:id/answer-questions</code> with <code>{ askId, answers }</code>.</li><li>The pending tool call resolves with <code>{ askId, answers }</code> and the agent continues its session.</li></ol><p><code>ask_questions</code> is only available when the executing context is a conversation — workflow runs cannot invoke it.</p><h2 id="persistence-model" tabindex="-1">Persistence Model <a class="header-anchor" href="#persistence-model" aria-label="Permalink to &quot;Persistence Model&quot;">​</a></h2><ul><li><code>conversations</code> stores the thread header, selected agent, and timestamps.</li><li><code>conversation_messages</code> stores each turn, its status, any assistant error, and assistant metadata such as agent/model selection, reasoning text, live tool activity, and tool trace.</li><li>If an agent is deleted later, the existing conversation remains readable, but new turns are disabled.</li></ul><h2 id="typical-use-cases" tabindex="-1">Typical Use Cases <a class="header-anchor" href="#typical-use-cases" aria-label="Permalink to &quot;Typical Use Cases&quot;">​</a></h2><ul><li>Ask an agent ad hoc questions before formalizing the task into a workflow.</li><li>Validate an agent&#39;s prompt design interactively from its detail page.</li><li>Keep a lightweight working thread with an agent while still using workflows for repeatable automation.</li></ul>',28)])])}const g=t(n,[["render",i]]);export{p as __pageData,g as default};
